# ANTI-PATTERN: Naive training loop causing memory bloat
class BatsmanScorer(nn.Module):
    def __init__(self):
        super().__init__()
        self.layers = nn.Sequential(*[nn.Linear(512, 512) for _ in range(12)])

    def forward(self, boundary_features):
        return self.layers(boundary_features)

model = BatsmanScorer()
optimizer = torch.optim.Adam(model.parameters())

for epoch in range(100):
    for batch_idx, (runs_data, wicket_labels) in enumerate(cricket_loader):
        optimizer.zero_grad()
        scores = model(runs_data)
        loss = F.cross_entropy(scores, wicket_labels)
        loss.backward()  # ❌ All intermediate activations stored
        optimizer.step()
        if batch_idx % 10 == 0:
            print(f"Memory: {torch.cuda.memory_allocated() / 1e9:.2f}GB")  # Grows unbounded

# BEST PRACTICE: Mixed precision with gradient checkpointing
from torch.cuda.amp import autocast, GradScaler

class OptimizedBatsmanScorer(nn.Module):
    def __init__(self):
        super().__init__()
        self.layers = nn.Sequential(*[nn.Linear(512, 512) for _ in range(12)])

    def forward(self, boundary_features):
        return self.layers(boundary_features)

model = OptimizedBatsmanScorer()
optimizer = torch.optim.Adam(model.parameters())
scaler = GradScaler()

for epoch in range(100):
    for batch_idx, (runs_data, wicket_labels) in enumerate(cricket_loader):
        optimizer.zero_grad()

        # ✅ FP16 forward pass reduces memory by 50%
        with autocast(dtype=torch.float16):
            scores = model(runs_data)
            loss = F.cross_entropy(scores, wicket_labels)

        # ✅ Scaled backward preserves gradient precision
        scaler.scale(loss).backward()
        scaler.unscale_(optimizer)
        torch.nn.utils.clip_grad_norm_(model.parameters(), 1.0)
        scaler.step(optimizer)
        scaler.update()

        if batch_idx % 10 == 0:
            print(f"Memory: {torch.cuda.memory_allocated() / 1e9:.2f}GB")  # Stable ~2-3GB

# For deeper networks, add selective checkpointing:
from torch.utils.checkpoint import checkpoint

class CheckpointedBatsmanScorer(nn.Module):
    def __init__(self):
        super().__init__()
        self.layers = nn.ModuleList([nn.Linear(512, 512) for _ in range(12)])

    def forward(self, x):
        for i, layer in enumerate(self.layers):
            if i % 2 == 0:  # ✅ Checkpoint every 2nd layer
                x = checkpoint(layer, x, use_reentrant=False)
            else:
                x = layer(x)
        return x
